// Extract the user's message content from the Discord interaction
const root = $input.first().json;
const body = root.body || root;

let userMessage = '';
let channelId = '';
let userId = '';
let username = '';

if (body.data && body.data.options) {
  const textOption = body.data.options.find((o) => o.name === 'command');
  userMessage = textOption ? textOption.value : '';
} else if (body.content) {
  userMessage = body.content.replace(/<@!?\d+>\s*/g, '').trim();
} else if (body.data && body.data.resolved) {
  userMessage = body.data.name || '';
}

channelId = body.channel_id || body.channel?.id || '';
userId = body.member?.user?.id || body.user?.id || '';
username = body.member?.user?.username || body.user?.username || 'Unknown';

return [{
  json: {
    userMessage,
    channelId,
    userId,
    username,
    source: body.source || 'discord',
    rawBody: body,
  }
}];

const aiResponse = $input.first().json.text || $input.first().json.content?.[0]?.text || '';

let parsed;
try {
  // Strip markdown code fences if present
  const clean = aiResponse.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = {
    action: 'error',
    error: 'Could not parse command. Try: "create issue Fix login bug" or "update ENG-123 to In Progress"'
  };
}

// Pass through original context
const original = $('Extract Message').first().json;

return [{
  json: {
    ...parsed,
    userMessage: original.userMessage,
    channelId: original.channelId,
    userId: original.userId,
    username: original.username
  }
}];

