mutation CreateIssue($title: String!, $description: String, $teamId: String!) {
  issueCreate(input: {
    title: $title
    description: $description
    teamId: $teamId
  }) {
    success
    issue {
      id
      identifier
      title
      url
      state { name }
      priority
    }
  }
}

query SearchIssues($query: String!) {
  issueSearch(query: $query, first: 10) {
    nodes {
      id
      identifier
      title
      state { name }
      assignee { name email }
      priority
      url
    }
  }
}

query FindWorkflowStates($teamId: String!) {
  team(id: $teamId) {
    states {
      nodes {
        id
        name
      }
    }
  }
}

