// Format a nice Discord response for "create issue" result
const result = $input.first().json;
const issue = result.data?.issueCreate?.issue;
const originalAction = $('Parse AI Response').first().json;

if (!issue) {
  return [{ json: { message: '❌ Failed to create issue. Please check your Linear API key and Team ID.' } }];
}

const priorityEmoji = {
  0: '⚪', // no priority
  1: '🔴', // urgent
  2: '🟠', // high
  3: '🟡', // medium
  4: '🔵'  // low
};

const emoji = priorityEmoji[issue.priority] || '⚪';

return [{
  json: {
    message: `✅ **Issue Created!**\n\n${emoji} **[${issue.identifier}](${issue.url})** ${issue.title}\n📋 Status: ${issue.state?.name || 'Backlog'}\n\n*Created by @${originalAction.username}*`
  }
}];

// Find the matching state and update the issue
const statesResult = $input.first().json;
const originalAction = $('Parse AI Response').first().json;

const states = statesResult.data?.team?.states?.nodes || [];
const targetStatus = originalAction.params?.status || '';

const matchedState = states.find((s) =>
  s.name.toLowerCase() === targetStatus.toLowerCase() ||
  s.name.toLowerCase().includes(targetStatus.toLowerCase()),
);

if (!matchedState) {
  const available = states.map((s) => s.name).join(', ');
  return [{ json: {
    message: `❌ Status "${targetStatus}" not found.\nAvailable statuses: ${available}`,
    skip: true,
  }}];
}

return [{
  json: {
    stateId: matchedState.id,
    stateName: matchedState.name,
    issueIdentifier: originalAction.params?.issue_id,
    titleHint: originalAction.params?.title_hint,
    username: originalAction.username,
    skip: false,
  }
}];

// Format search results for Discord
const result = $input.first().json;
const issues = result.data?.issueSearch?.nodes || [];
const originalAction = $('Parse AI Response').first().json;

if (issues.length === 0) {
  return [{ json: { message: `🔍 No issues found for: "${originalAction.params?.query}"` } }];
}

const priorityLabel = { 0: 'None', 1: '🔴 Urgent', 2: '🟠 High', 3: '🟡 Medium', 4: '🔵 Low' };

const lines = issues.slice(0, 8).map(issue => {
  const assignee = issue.assignee?.name || 'Unassigned';
  const priority = priorityLabel[issue.priority] || 'None';
  return `• **[${issue.identifier}](${issue.url})** ${issue.title}\n  └ ${issue.state?.name} · ${assignee} · ${priority}`;
}).join('\n\n');

return [{
  json: {
    message: `🔍 **Found ${issues.length} issue(s)** for "${originalAction.params?.query}":\n\n${lines}${issues.length > 8 ? `\n\n*...and ${issues.length - 8} more*` : ''}`
  }
}];

// Find the assignee from team members list
const membersResult = $input.first().json;
const originalAction = $('Parse AI Response').first().json;

const members = membersResult.data?.team?.members?.nodes || [];
const targetAssignee = (originalAction.params?.assignee || '').trim();
const discordUser = (originalAction.username || '').trim();

const matchedMember = members.find((m) => {
  const name = (m.name || '').toLowerCase();
  const email = (m.email || '').toLowerCase();
  const emailUser = email.split('@')[0] || '';
  const t = targetAssignee.toLowerCase();
  const d = discordUser.toLowerCase();
  return (
    (t && (name.includes(t) || email.includes(t) || emailUser.includes(t))) ||
    (d && (name.includes(d) || emailUser === d || email.includes(d)))
  );
});

if (!matchedMember) {
  const names = members.map((m) => `${m.name}${m.email ? ` (${m.email})` : ''}`).join(', ');
  return [{ json: {
    message: `❌ Team member "${targetAssignee || discordUser}" not found.\nTeam members: ${names || 'none'}`,
    skip: true,
  }}];
}

return [{
  json: {
    assigneeId: matchedMember.id,
    assigneeName: matchedMember.name,
    issueIdentifier: originalAction.params?.issue_id,
    titleHint: originalAction.params?.title_hint,
    username: originalAction.username,
    skip: false,
  }
}];

// Handle add_comment and error/unknown actions
const action = $json.action;
const params = $json.params || {};

if (action === 'add_comment') {
  return [{ json: { 
    action: 'add_comment',
    issueId: params.issue_id,
    titleHint: params.title_hint,
    comment: params.comment,
    username: $json.username
  }}];
}

if (action === 'clarification_needed' || ($json.clarification_needed && $json.clarification_needed !== null)) {
  return [{ json: { message: `❓ ${$json.clarification_needed}` } }];
}

return [{ json: { message: `❌ I didn\'t understand that command. Try:\n• "create issue Fix the login bug high priority"\n• "update ENG-123 to In Progress"\n• "assign ENG-456 to John"\n• "search for open bugs"\n• "add comment to ENG-789: needs more info"` } }];

