const issue = result.data?.issueUpdate?.issue;
const stateInfo = $('Prepare Update').first().json;

if (!issue) {
  return [{ json: { message: '❌ Failed to update issue status. Make sure the issue ID is correct.' } }];
}

return [{
  json: {
    message: `✅ **Status Updated!**\n\n**[${issue.identifier}](${issue.url})** ${issue.title}\n📋 New Status: **${issue.state?.name}**\n\n*Updated by @${stateInfo.username}*`
  }
}];

const result = $input.first().json;
const issue = result.data?.issueUpdate?.issue;
const assigneeInfo = $('Prepare Assign').first().json;

if (!issue) {
  return [{ json: { message: '❌ Failed to assign issue. Make sure the issue ID is correct.' } }];
}

return [{
  json: {
    message: `✅ **Issue Assigned!**\n\n**[${issue.identifier}](${issue.url})** ${issue.title}\n👤 Assigned to: **${issue.assignee?.name}**\n\n*Assigned by @${assigneeInfo.username}*`
  }
}];
